#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
int n,m,k,s1[N],s2[N];
long long ans;
int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
        for(int j=i;j<=k;j+=i)
            s1[j]++;
    for(int i=1;i<=m;i++)
        for(int j=i;j<=k;j+=i)
            s2[j]++;
    for(int i=1;i<=k;i++)
        ans+=1LL*i*s1[i]*s2[i];
    printf("%lld",ans);
    return 0;
}
